css:
:root {
  --primary: #0b4f8a;
  --primary-dark: #07345c;
  --primary-soft: #eef6ff;
  --text: #17202a;
  --muted: #596778;
  --line: #d7e0ea;
  --page: #ffffff;
  --screen: #eef1f5;
  --panel: #f8fbff;
}

* {
  box-sizing: border-box;
}

html {
  font-size: 14.5px;
}

body {
  margin: 0;
  background: var(--screen);
  color: var(--text);
  font-family: Arial, Helvetica, sans-serif;
  line-height: 1.28;
}

.cv {
  width: 210mm;
  min-height: 297mm;
  margin: 18px auto;
  padding: 10mm 12mm 11mm;
  background: var(--page);
  box-shadow: 0 12px 36px rgba(15, 23, 42, 0.15);
  border-top: 5px solid var(--primary);
}

.header {
  display: grid;
  grid-template-columns: 1fr 65mm;
  gap: 9mm;
  align-items: start;
  padding-bottom: 5mm;
  border-bottom: 1.4px solid var(--primary);
}

.role {
  margin: 0 0 4px;
  color: var(--primary);
  font-size: 0.88rem;
  font-weight: 800;
  letter-spacing: 0.07em;
  text-transform: uppercase;
}

h1 {
  margin: 0;
  color: #0f172a;
  font-size: 1.95rem;
  line-height: 1.03;
  letter-spacing: -0.03em;
}

.tagline {
  max-width: 118mm;
  margin: 6px 0 0;
  color: var(--muted);
  font-size: 0.95rem;
}

.header-side {
  display: grid;
  grid-template-columns: 24mm 1fr;
  gap: 4mm;
  align-items: center;
}

.photo {
  width: 24mm;
  height: 24mm;
  display: block;
  border: 1px solid var(--line);
  border-radius: 50%;
  object-fit: cover;
  background: #f3f6fa;
}

.contact {
  display: grid;
  grid-template-columns: 1fr;
  gap: 2px;
  margin: 0;
  color: var(--text);
  font-size: 0.79rem;
  font-style: normal;
  text-align: right;
}

.contact a {
  color: inherit;
  text-decoration: none;
}

.section {
  margin-top: 4.4mm;
}

h2 {
  display: flex;
  align-items: center;
  gap: 7px;
  margin: 0 0 5px;
  color: var(--primary-dark);
  font-size: 0.86rem;
  line-height: 1.2;
  letter-spacing: 0.055em;
  text-transform: uppercase;
}

h2::after {
  content: "";
  flex: 1;
  height: 1px;
  background: var(--line);
}

p {
  margin: 0 0 5px;
}

.summary p {
  padding: 3mm 4mm;
  border-left: 3px solid var(--primary);
  background: var(--panel);
  color: var(--text);
  font-size: 0.9rem;
}

.strengths {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 3.2mm;
  margin: 0;
  padding: 0;
  list-style: none;
}

.strengths li {
  padding: 3mm 3.4mm;
  border: 1px solid var(--line);
  border-radius: 7px;
  background: #ffffff;
  font-size: 0.82rem;
}

.entry {
  position: relative;
  padding: 0 0 3.4mm 4.6mm;
  margin-bottom: 3.2mm;
  border-left: 2px solid var(--line);
}

.entry::before {
  content: "";
  position: absolute;
  left: -4.5px;
  top: 3px;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--primary);
}

.entry:last-child {
  margin-bottom: 0;
}

.entry-header {
  display: flex;
  justify-content: space-between;
  gap: 8mm;
  align-items: flex-start;
  margin-bottom: 2px;
}

h3 {
  margin: 0;
  color: #111827;
  font-size: 0.94rem;
  line-height: 1.2;
}

.meta {
  margin: 1px 0 0;
  color: var(--muted);
  font-size: 0.82rem;
  font-style: italic;
}

.date {
  flex: 0 0 auto;
  margin: 0;
  color: var(--primary-dark);
  font-size: 0.78rem;
  font-weight: 700;
  white-space: nowrap;
}

ul {
  margin: 3px 0 0 16px;
  padding: 0;
}

li {
  margin-bottom: 1.5px;
  padding-left: 1px;
}

.compact-entry p,
.education-entry p {
  font-size: 0.86rem;
}

.skills-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 3.2mm;
}

.skill-group {
  padding: 3mm 3.4mm;
  border: 1px solid var(--line);
  border-radius: 7px;
  background: var(--panel);
}

.skill-group h3 {
  margin-bottom: 2px;
  color: var(--primary-dark);
  font-size: 0.84rem;
}

.skill-group p {
  margin: 0;
  font-size: 0.78rem;
}

.bottom-grid {
  display: grid;
  grid-template-columns: 1.55fr 0.82fr;
  gap: 6mm;
}

.education-entry,
.language-list {
  padding: 3mm 3.4mm;
  border: 1px solid var(--line);
  border-radius: 7px;
  background: #ffffff;
}

.language-list {
  margin: 0;
  padding-left: 6mm;
}

.language-list li {
  margin-bottom: 2px;
}

@media print {
  @page {
    size: A4;
    margin: 8mm 9mm;
  }

  body {
    background: #ffffff;
  }

  .cv {
    width: auto;
    min-height: auto;
    margin: 0;
    padding: 0;
    box-shadow: none;
    border-top-width: 5px;
  }

  .header,
  .summary p,
  .strengths li,
  .entry,
  .skill-group,
  .education-entry,
  .language-list {
    break-inside: avoid;
    page-break-inside: avoid;
  }

  a {
    color: inherit;
    text-decoration: none;
  }
}

@media (max-width: 820px) {
  .cv {
    width: 100%;
    min-height: auto;
    margin: 0;
    padding: 24px 18px;
    box-shadow: none;
  }

  .header,
  .strengths,
  .skills-grid,
  .bottom-grid {
    grid-template-columns: 1fr;
  }

  .header-side {
    grid-template-columns: 68px 1fr;
  }

  .photo {
    width: 68px;
    height: 68px;
  }

  .contact {
    text-align: left;
  }

  .entry-header {
    display: block;
  }

  .date {
    display: block;
    margin-top: 3px;
  }
}
